mapper.select:
select
    i.id,
    i.frame,
    i.customer,
    i.time,
    i.number,
    i.total,
    ib.money,
    i.people,
    i.examine,
    i.nucleus,
    i.user,
    i.data
from imy i
left join imy_bill ib on i.id = ib.pid
left join imy_info ii on i.id = ii.pid


        and i.customer = #{query.customer}


        and Date(i.time) between #{query.beginTime} and #{query.endTime}


        and i.number = #{query.number}


        and i.people = #{query.people}


        and i.user = #{query.user}


        and i.examine = #{query.examine}


        and i.nucleus = #{query.nucleus}


        and ii.account = #{query.data}


        and i.data = #{query.data}
